import React from 'react'
import styled from 'styled-components'
import searchImage from './static/search.png'

const NavbarWrapper = styled.div `
display:flex;
justify-content:space-between;
align-items:center;
width:90%;
height:20vh
`

const BrandName = styled.div `
font-size:2rem;
font-weight:heavy;
letter-spacing:10px;
`

const SearchBar = styled.input `
display:flex;
justify-content:flex-end;
align-items:center;
width:50%;
height:40%;
backround-image:url(${searchImage})
background-position:center;
background-size:cover;
`

export default function Navbar () {
	return (
		<NavbarWrapper>
			<BrandName>CACTUS</BrandName>
			<SearchBar></SearchBar>
			<FeaturesWrapper>
				<Sell></Sell>
				<Shop></Shop>
				<SoppingCart></SoppingCart>
				<Me></Me>
			</FeaturesWrapper>
		</NavbarWrapper>
	)
}
